import React, { useEffect, useState, useCallback } from 'react';
import { useTable, useSortBy, useGlobalFilter, usePagination } from 'react-table';
import EditPurchase from './EditPurchase';

import './PurchaseFunc.css';

const PurchaseFunc = () => {
  const [purchases, setPurchases] = useState([]);
  const [editingPurchase, setEditingPurchase] = useState(null);

  useEffect(() => {
    if (!dataFetched) {
      fetchData();
      setDataFetched(true);
    }
  }, [dataFetched]);

  const fetchData = async () => {
    try {
      const response = await fetch('http://localhost:8081/PurchasesAPI');
      if (!response.ok) {
        throw new Error('Failed to fetch data');
      }
      const data = await response.json();
      setPurchases(data);
    } catch (error) {
      console.error('Error fetching data:', error);
    }
  };
  const handleAddPurchase = (event) => {
    event.preventDefault(); // Prevent the default form submission behavior

    // Get the form data
    const formData = new FormData(event.target);
    const newPurchase = {
      location: formData.get('location'),
      materialid: formData.get('materialid'),
      quantity: formData.get('quantity'),
      date: formData.get('date'),
    };

    // Make a POST request to add the new purchase
    fetch('http://localhost:8081/PurchasesAPI', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
      },
      body: JSON.stringify(newPurchase),
    })
      .then((response) => {
        if (!response.ok) {
          throw new Error('Failed to add the purchase.');
        }
        // Update the local state with the new purchase immediately
        return response.json();
      })
      .then((data) => {
        // Fetch the updated data and refresh the state
        fetchData();
      })
      .catch((error) => {
        console.error('Error adding the purchase:', error);
        // Handle the error, show a notification, or display a user-friendly message
      });
  };

  const handleEdit = useCallback((purchase) => {
    if (editingPurchase && editingPurchase.id === purchase.id) {
      alert('Purchase is already being edited.');
      return;
    }

    setEditingPurchase(purchase);
  }, [editingPurchase]);

  const handleUpdate = useCallback((updatedPurchase) => {
    // Make a PUT request to update the purchase
    fetch(`http://localhost:8081/PurchasesAPI/${updatedPurchase.id}`, {
      method: 'PUT',
      headers: {
        'Content-Type': 'application/json',
      },
      body: JSON.stringify(updatedPurchase),
    })
      .then((response) => {
        if (!response.ok) {
          throw new Error('Failed to update the purchase.');
        }
        // Refetch the data to get the updated results
        fetchData();
        setEditingPurchase(null);
      })
      .catch((error) => {
        console.error('Error updating the purchase:', error);
        // Handle the error, show a notification, or display a user-friendly message
      });
  }, []);

  const handleDelete = useCallback((deletedPurchase) => {
    const isConfirmed = window.confirm('Are you sure you want to delete this purchase?');

    if (isConfirmed) {
      fetch(`http://localhost:8081/PurchasesAPI/${deletedPurchase.id}`, {
        method: 'DELETE',
      })
        .then((response) => {
          if (!response.ok) {
            throw new Error('Failed to delete the purchase.');
          }
          // Remove the deleted purchase from the local state
          setPurchases((prevPurchases) =>
            prevPurchases.filter((purchase) => purchase.id !== deletedPurchase.id)
          );
        })
        .catch((error) => {
          console.error('Error deleting the purchase:', error);
        });
    }
  }, []);

  const columns = React.useMemo(
    () => [
      { Header: 'ID', accessor: 'id' },
      { Header: 'Location', accessor: 'location' },
      { Header: 'Material ID', accessor: 'materialid' },
      { Header: 'Quantity', accessor: 'quantity' },
      { Header: 'Date', accessor: 'date' },
      {
        Header: 'Actions',
        accessor: 'actions',
        Cell: ({ row }) => (
          <div>
            <button onClick={() => handleEdit(row.original)}>Edit</button>
            <button onClick={() => handleDelete(row.original)}>Delete</button>
          </div>
        ),
      },
    ],
    [handleEdit, handleDelete]
  );
  
  const {
    getTableProps,
    getTableBodyProps,
    headerGroups,
    page,
    prepareRow,
    state: { pageIndex, pageSize, globalFilter },
    gotoPage,
    nextPage,
    previousPage,
    canNextPage,
    canPreviousPage,
    setPageSize,
    setGlobalFilter,
  } = useTable(
    {
      columns,
      data: purchases,
      initialState: {
        pageIndex: 0,
        pageSize: 10,
      },
    },
    useGlobalFilter,
    useSortBy,
    usePagination
  );

  if (purchases.length === 0) {
    return <div>Loading...</div>;
  }

  return (
    <div>
      <form onSubmit={handleAddPurchase}>
        <input type="text" name="location" placeholder="Location" />
        <input type="text" name="materialid" placeholder="Material ID" />
        <input type="number" name="quantity" placeholder="Quantity" />
        <input type="date" name="date" />
        <button type="submit">Add Purchase</button>
      </form>
      <div className="search">
        <input
          type="text"
          value={globalFilter || ''}
          onChange={(e) => setGlobalFilter(e.target.value)}
          placeholder="Search..."
        />
      </div>
      <table {...getTableProps()} className="purchase-table">
        <thead>
          {headerGroups.map((headerGroup) => (
            <tr {...headerGroup.getHeaderGroupProps()}>
              {headerGroup.headers.map((column) => (
                <th {...column.getHeaderProps(column.getSortByToggleProps())}>
                  {column.render('Header')}
                  <span>{column.isSorted ? (column.isSortedDesc ? ' 🔽' : ' 🔼') : ''}</span>
                </th>
              ))}
            </tr>
          ))}
        </thead>
        <tbody {...getTableBodyProps()}>
          {page.map((row) => {
            prepareRow(row);
            return (
              <React.Fragment key={row.getRowProps().key}>
                <tr {...row.getRowProps()}>
                  {row.cells.map((cell) => (
                    <td {...cell.getCellProps()}>{cell.render('Cell')}</td>
                  ))}
                </tr>
                {editingPurchase && editingPurchase.id === row.original.id && (
                  <tr>
                    <td colSpan={columns.length}>
                      <EditPurchase purchase={editingPurchase} handleUpdate={handleUpdate} />
                    </td>
                  </tr>
                )}
              </React.Fragment>
            );
          })}
        </tbody>
      </table>
      <div>
        <button onClick={() => previousPage()} disabled={!canPreviousPage}>
          Previous
        </button>
        <button onClick={() => nextPage()} disabled={!canNextPage}>
          Next
        </button>
        <span>
          Page{' '}
          <strong>
            {pageIndex + 1} of {Math.ceil(purchases.length / pageSize)}
          </strong>{' '}
        </span>
        <span>
          | Go to page:{' '}
          <input
            type="number"
            defaultValue={pageIndex + 1}
            onChange={(e) => {
              const page = e.target.value ? Number(e.target.value) - 1 : 0;
              gotoPage(page);
            }}
            style={{ width: '50px' }}
          />
        </span>
        <select
          value={pageSize}
          onChange={(e) => {
            setPageSize(Number(e.target.value));
          }}
        >
          {[10, 25, 50].map((pageSize) => (
            <option key={pageSize} value={pageSize}>
              Show {pageSize}
            </option>
          ))}
        </select>
      </div>
    </div>
  );
};

export default PurchaseFunc;
